8544 VPRecipeBase *
8545 VPRecipeBuilder::tryToCreateWidenRecipe(Instruction *Instr,
8546                                         ArrayRef<VPValue *> Operands,
8547                                         VFRange &Range, VPBasicBlock *VPBB) {
8548   // First, check for specific widening recipes that deal with inductions, Phi
8549   // nodes, calls and memory operations.
8550   VPRecipeBase *Recipe;
8551   if (auto *Phi = dyn_cast<PHINode>(Instr)) {
8552     if (Phi->getParent() != OrigLoop->getHeader())
8553       return tryToBlend(Phi, Operands);
8554 
8555     if ((Recipe = tryToOptimizeInductionPHI(Phi, Operands, Range)))
8556       return Recipe;
8557 
8558     VPHeaderPHIRecipe *PhiRecipe = nullptr;
8559     assert((Legal->isReductionVariable(Phi) ||
8560             Legal->isFixedOrderRecurrence(Phi)) &&
8561            "can only widen reductions and fixed-order recurrences here");
8562     VPValue *StartV = Operands[0];
8563     if (Legal->isReductionVariable(Phi)) {
8564       const RecurrenceDescriptor &RdxDesc =
8565           Legal->getReductionVars().find(Phi)->second;
8566       assert(RdxDesc.getRecurrenceStartValue() ==
8567              Phi->getIncomingValueForBlock(OrigLoop->getLoopPreheader()));
8568       PhiRecipe = new VPReductionPHIRecipe(Phi, RdxDesc, *StartV,
8569                                            CM.isInLoopReduction(Phi),
8570                                            CM.useOrderedReductions(RdxDesc));
8571     } else {
8572       // TODO: Currently fixed-order recurrences are modeled as chains of
8573       // first-order recurrences. If there are no users of the intermediate
8574       // recurrences in the chain, the fixed order recurrence should be modeled
8575       // directly, enabling more efficient codegen.
8576       PhiRecipe = new VPFirstOrderRecurrencePHIRecipe(Phi, *StartV);
8577     }
8578 
8579     PhisToFix.push_back(PhiRecipe);
8580     return PhiRecipe;
8581   }
8582 
8583   if (isa<TruncInst>(Instr) && (Recipe = tryToOptimizeInductionTruncate(
8584                                     cast<TruncInst>(Instr), Operands, Range)))
8585     return Recipe;
8586 
8587   // All widen recipes below deal only with VF > 1.
8588   if (LoopVectorizationPlanner::getDecisionAndClampRange(
8589           [&](ElementCount VF) { return VF.isScalar(); }, Range))
8590     return nullptr;
8591 
8592   if (auto *CI = dyn_cast<CallInst>(Instr))
8593     return tryToWidenCall(CI, Operands, Range);
8594 
8595   if (StoreInst *SI = dyn_cast<StoreInst>(Instr))
8596     if (auto HistInfo = Legal->getHistogramInfo(SI))
8597       return tryToWidenHistogram(*HistInfo, Operands);
8598 
8599   if (isa<LoadInst>(Instr) || isa<StoreInst>(Instr))
8600     return tryToWidenMemory(Instr, Operands, Range);
8601 
8602   if (!shouldWiden(Instr, Range))
8603     return nullptr;
8604 
8605   if (auto *GEP = dyn_cast<GetElementPtrInst>(Instr))
8606     return new VPWidenGEPRecipe(GEP,
8607                                 make_range(Operands.begin(), Operands.end()));
8608 
8609   if (auto *SI = dyn_cast<SelectInst>(Instr)) {
8610     return new VPWidenSelectRecipe(
8611         *SI, make_range(Operands.begin(), Operands.end()));
8612   }
8613 
8614   if (auto *CI = dyn_cast<CastInst>(Instr)) {
8615     return new VPWidenCastRecipe(CI->getOpcode(), Operands[0], CI->getType(),
8616                                  *CI);
8617   }
8618 
8619   return tryToWiden(Instr, Operands, VPBB);
8620 }
